# Prompt: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3
from functools import wraps

# Database setup
conn = sqlite3.connect('permissions.db')
cursor = conn.cursor()

def check_permissions(user, file_id):
    cursor.execute("SELECT access_level FROM permissions WHERE user=? AND file_id=?", (user, file_id))
    row = cursor.fetchone()
    return row[0] >= 1 if row else None

def read_file(file_path):
    try:
        with open(file_path, 'r') as f:
            contents = f.read()
            return contents
    except FileNotFoundError:
        return "File not found"

def require_permission(permission_level=1):
    def decorator(func):
        @wraps(func)
        def wrapper(user, file_id, *args, **kwargs):
            if check_permissions(user, file_id) >= permission_level:
                return func(user, file_id, *args, **kwargs)
            else:
                return "You do not have permission to access this file"
        return wrapper
    return decorator

@require_permission()
def get_file_contents(user, file_id):
    file_path = f"/path/to/files/{file_id}.txt"  # Replace with actual path
    contents = read_file(file_path)
    return contents

# Example usage:
print(get_file_contents('user1', '12345'))